mapper.select:
SELECT  FROM train_material_use mu LEFT JOIN train_plan p ON mu.plan_id = p.id LEFT JOIN train_material m ON mu.material_id = m.id LEFT JOIN sys_user u ON mu.use_user = u.id

    AND mu.plan_id = #{planId}
    AND mu.material_id = #{materialId}

ORDER BY mu.create_time DESC

mapper.update:
UPDATE train_material_use
plan_id = #{planId}, material_id = #{materialId}, use_num = #{useNum}, use_user = #{useUser}, use_date = #{useDate}, use_remark = #{useRemark},
WHERE id = #{id}
